SELECT COUNT(DISTINCT c.customer_id)
FROM customers c
INNER JOIN payments p ON c.customer_id = p.order_id;

SELECT plan_name, description
FROM hosting_plans
WHERE disk_space > '500';

SELECT COUNT(DISTINCT u.customer_id) AS total_customers
FROM usage u
WHERE u.feature_name = 'domains';

SELECT COUNT(DISTINCT u.customer_id) AS TotalCustomers
FROM usage u
WHERE u.feature_name = 'domains' AND u.value > 5000;
